                    crate::platform::PlatformError::command_failed(
                        crate::platform::PlatformOperation::OpenPath,
                        path.display().to_string(),
                        "raw path failure",
                    ),
                )
            } else {
                crate::platform::desktop::DesktopActionResult::success(
                    crate::platform::PlatformOperation::OpenPath,
                    path.display().to_string(),
                )
            }
        }

